import { useState, useEffect, useRef, useCallback } from 'react'
import { useNavigate } from 'react-router-dom'
import {
    Plane, Train, Bus, Layers, MapPin, Calendar, Users,
    ChevronDown, Search, ArrowLeftRight, X
} from 'lucide-react'
import { stationApi } from '../api/axios'

/* ═══════════════════════════════════════════════════════
   CONSTANTS
═══════════════════════════════════════════════════════ */
const MODES = [
    { id: 'COMBINED', label: 'Combined', icon: Layers, color: 'text-purple-400', activeBg: 'bg-purple-500/10 border-purple-500/30 dark:bg-purple-500/10 dark:border-purple-500/30' },
    { id: 'FLIGHT', label: 'Flights', icon: Plane, color: 'text-sky-400', activeBg: 'bg-sky-500/10 border-sky-500/30 dark:bg-sky-500/10 dark:border-sky-500/30' },
    { id: 'TRAIN', label: 'Trains', icon: Train, color: 'text-emerald-400', activeBg: 'bg-emerald-500/10 border-emerald-500/30 dark:bg-emerald-500/10 dark:border-emerald-500/30' },
    { id: 'BUS', label: 'Buses', icon: Bus, color: 'text-amber-400', activeBg: 'bg-amber-500/10 border-amber-500/30 dark:bg-amber-500/10 dark:border-amber-500/30' },
]

const FLIGHT_CLASSES = ['Economy', 'Premium Economy', 'Business', 'First Class']
const TRAIN_CLASSES = ['Sleeper (SL)', 'AC 3-Tier (3A)', 'AC 2-Tier (2A)', 'AC 1st Class (1A)', '2nd Sitting (2S)']
const BUS_CLASSES = ['Seater', 'Sleeper', 'AC Seater', 'AC Sleeper', 'AC Volvo']
const COMBINED_MODES = [
    { id: 'BALANCED', label: '⚖️ Balanced' },
    { id: 'CHEAPEST', label: '💰 Cheapest' },
    { id: 'FASTEST', label: '⚡ Fastest' },
]
const PASSENGERS = [1, 2, 3, 4, 5, 6]

/* ═══════════════════════════════════════════════════════
   CITY AUTOCOMPLETE INPUT
═══════════════════════════════════════════════════════ */
function CityInput({ id, label, icon: Icon, iconColor, value, onChange, placeholder }) {
    const [query, setQuery] = useState(value || '')
    const [suggestions, setSuggestions] = useState([])
    const [open, setOpen] = useState(false)
    const [loading, setLoading] = useState(false)
    const containerRef = useRef(null)
    const debounceRef = useRef(null)

    // Sync external value resets (e.g. swap button)
    useEffect(() => { setQuery(value || '') }, [value])

    // Close on outside click
    useEffect(() => {
        const handleClick = (e) => {
            if (containerRef.current && !containerRef.current.contains(e.target)) {
                setOpen(false)
            }
        }
        document.addEventListener('mousedown', handleClick)
        return () => document.removeEventListener('mousedown', handleClick)
    }, [])

    const fetchCities = useCallback((q) => {
        if (q.length < 1) { setSuggestions([]); setOpen(false); return }
        clearTimeout(debounceRef.current)
        debounceRef.current = setTimeout(async () => {
            setLoading(true)
            try {
                const res = await stationApi.search(q)
                // The API may return stations; extract unique cities
                const cities = [...new Set(
                    (res.data || []).map(s => s.city || s.name || s).filter(Boolean)
                )]
                setSuggestions(cities)
                setOpen(cities.length > 0)
            } catch {
                setSuggestions([])
            } finally {
                setLoading(false)
            }
        }, 220)
    }, [])

    const handleChange = (e) => {
        const v = e.target.value
        setQuery(v)
        onChange(v)
        fetchCities(v)
    }

    const handleSelect = (city) => {
        setQuery(city)
        onChange(city)
        setOpen(false)
        setSuggestions([])
    }

    const handleClear = () => {
        setQuery('')
        onChange('')
        setSuggestions([])
        setOpen(false)
    }

    return (
        <div className="relative" ref={containerRef}>
            {/* Icon */}
            <div className="absolute left-3 top-1/2 -translate-y-1/2 z-10 pointer-events-none">
                <Icon className={`w-4 h-4 ${iconColor}`} />
            </div>

            <label
                htmlFor={id}
                className="absolute left-9 right-8 top-2 text-[10px] font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wide z-10 pointer-events-none truncate"
            >
                {label}
            </label>

            {/* Input */}
            <input
                id={id}
                type="text"
                value={query}
                onChange={handleChange}
                onFocus={() => query.length > 0 && suggestions.length > 0 && setOpen(true)}
                placeholder={placeholder}
                required
                autoComplete="off"
                className="input-field pl-9 pt-5 pb-1.5 h-14 text-sm pr-8 truncate"
            />

            {/* Clear button */}
            {query && (
                <button
                    type="button"
                    onClick={handleClear}
                    className="absolute right-2.5 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600 dark:hover:text-gray-200 transition-colors"
                >
                    <X className="w-3.5 h-3.5" />
                </button>
            )}

            {/* Dropdown suggestions */}
            {open && (
                <div className="absolute top-full left-0 right-0 mt-1 z-50 bg-white dark:bg-dark-700 border border-gray-200 dark:border-white/10 rounded-xl shadow-xl overflow-hidden animate-slide-down">
                    {loading ? (
                        <div className="px-4 py-3 text-xs text-gray-400 dark:text-gray-500">Searching...</div>
                    ) : suggestions.map((city, i) => (
                        <button
                            key={i}
                            type="button"
                            onMouseDown={() => handleSelect(city)}
                            className="w-full text-left px-4 py-3 text-sm text-gray-800 dark:text-gray-200 hover:bg-primary-50 dark:hover:bg-dark-600 hover:text-primary-700 dark:hover:text-primary-400 transition-colors flex items-center gap-3 border-b last:border-0 border-gray-100 dark:border-white/5"
                        >
                            <MapPin className="w-3.5 h-3.5 text-gray-400 dark:text-gray-500 flex-shrink-0" />
                            {city}
                        </button>
                    ))}
                </div>
            )}
        </div>
    )
}

/* ═══════════════════════════════════════════════════════
   FIELD SELECT (Passengers, Class, Sort)
═══════════════════════════════════════════════════════ */
function FieldSelect({ label, icon: Icon, iconColor, value, onChange, options, fullLabel = false }) {
    return (
        <div className="relative">
            {Icon && (
                <div className="absolute left-3 top-1/2 -translate-y-1/2 z-10 pointer-events-none">
                    <Icon className={`w-4 h-4 ${iconColor}`} />
                </div>
            )}
            <label className={`absolute ${Icon ? 'left-9' : 'left-3'} right-6 top-2 text-[10px] font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wide z-10 pointer-events-none truncate`}>
                {label}
            </label>
            <select
                value={value}
                onChange={e => onChange(e.target.value)}
                className={`input-field ${Icon ? 'pl-9' : 'pl-3'} pt-5 pb-1.5 h-14 text-sm appearance-none pr-8 cursor-pointer truncate`}
            >
                {options.map(o => (
                    <option key={typeof o === 'object' ? o.id : o} value={typeof o === 'object' ? o.id : o}>
                        {typeof o === 'object' ? o.label : o}
                    </option>
                ))}
            </select>
            <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 dark:text-gray-500 pointer-events-none" />
        </div>
    )
}

/* ═══════════════════════════════════════════════════════
   MAIN HERO SEARCH CARD
═══════════════════════════════════════════════════════ */
export default function HeroSearchCard() {
    const navigate = useNavigate()
    const today = new Date().toISOString().split('T')[0]

    const [mode, setMode] = useState('COMBINED')
    const [origin, setOrigin] = useState('')
    const [destination, setDestination] = useState('')
    const [travelDate, setTravelDate] = useState(today)
    const [passengers, setPassengers] = useState('1')
    const [seatClass, setSeatClass] = useState('Economy')
    const [optimizationMode, setOptimizationMode] = useState('BALANCED')
    const [swapAnim, setSwapAnim] = useState(false)

    // Reset class to mode-appropriate default when mode changes
    useEffect(() => {
        if (mode === 'FLIGHT') setSeatClass('Economy')
        if (mode === 'TRAIN') setSeatClass('Sleeper (SL)')
        if (mode === 'BUS') setSeatClass('Seater')
        if (mode === 'COMBINED') setSeatClass('Economy')
    }, [mode])

    const classOptions = () => {
        if (mode === 'TRAIN') return TRAIN_CLASSES
        if (mode === 'BUS') return BUS_CLASSES
        return FLIGHT_CLASSES
    }

    const handleSwap = () => {
        setOrigin(destination)
        setDestination(origin)
        setSwapAnim(v => !v)
    }

    const handleSearch = (e) => {
        e.preventDefault()
        navigate('/search', {
            state: {
                searchParams: {
                    originCity: origin.trim(),
                    destinationCity: destination.trim(),
                    travelDate,
                    optimizationMode,
                    passengers: Number(passengers),
                    seatClass,
                    transportMode: mode !== 'COMBINED' ? mode : undefined,
                }
            }
        })
    }

    return (
        <div className="w-full max-w-4xl mx-auto">
            {/* ── MODE TABS ── */}
            <div className="flex gap-2 mb-4 overflow-x-auto pb-1 scrollbar-hide">
                {MODES.map(m => {
                    const Icon = m.icon
                    const active = mode === m.id
                    return (
                        <button
                            key={m.id}
                            type="button"
                            onClick={() => setMode(m.id)}
                            className={`
                                flex-shrink-0 flex items-center gap-1.5 px-4 py-2 rounded-xl text-sm font-semibold
                                border transition-all duration-200
                                ${active
                                    ? `${m.activeBg} ${m.color} scale-105 shadow-lg`
                                    : 'bg-gray-100 dark:bg-dark-700/60 border-gray-200 dark:border-white/5 text-gray-500 dark:text-gray-400 hover:text-gray-900 dark:hover:text-white hover:border-gray-300 dark:hover:border-white/10'
                                }
                            `}
                        >
                            <Icon className={`w-4 h-4 ${active ? m.color : ''}`} />
                            {m.label}
                        </button>
                    )
                })}
            </div>

            {/* ── SEARCH CARD ── */}
            <form onSubmit={handleSearch} className="bg-white/90 dark:bg-dark-800/80 backdrop-blur-xl border border-gray-200 dark:border-white/10 rounded-2xl shadow-xl dark:shadow-2xl p-6 sm:p-8 space-y-5">

                {/* From / To with city dropdown */}
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 relative">
                    <CityInput
                        id="search-from"
                        label="From"
                        icon={MapPin}
                        iconColor="text-primary-500 dark:text-primary-400"
                        value={origin}
                        onChange={setOrigin}
                        placeholder="Origin City"
                    />

                    {/* Swap */}
                    <button
                        type="button"
                        onClick={handleSwap}
                        className={`
                            absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 z-20
                            hidden sm:flex w-8 h-8 rounded-full items-center justify-center
                            bg-white dark:bg-dark-600 border-2 border-gray-200 dark:border-white/10
                            hover:bg-primary-600 hover:border-primary-500 hover:text-white hover:shadow-lg hover:shadow-primary-500/20
                            transition-all duration-300 hover:scale-110 active:scale-95 text-gray-500 dark:text-gray-300
                            ${swapAnim ? 'rotate-180' : ''}
                        `}
                    >
                        <ArrowLeftRight className="w-3.5 h-3.5" />
                    </button>

                    <CityInput
                        id="search-to"
                        label="To"
                        icon={MapPin}
                        iconColor="text-emerald-500 dark:text-emerald-400"
                        value={destination}
                        onChange={setDestination}
                        placeholder="Destination City"
                    />
                </div>

                {/* ── SECOND ROW: context-sensitive fields ── */}
                <div className={`grid gap-3 ${mode === 'COMBINED' ? 'grid-cols-1 xs:grid-cols-2 lg:grid-cols-4' : 'grid-cols-1 xs:grid-cols-2 lg:grid-cols-3'}`}>

                    {/* Date — always present */}
                    <div className="relative">
                        <div className="absolute left-3 top-1/2 -translate-y-1/2 z-10 pointer-events-none">
                            <Calendar className="w-4 h-4 text-purple-500 dark:text-purple-400" />
                        </div>
                        <label className="absolute left-9 right-4 top-2 text-[10px] font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wide z-10 pointer-events-none truncate">
                            Date
                        </label>
                        <input
                            type="date"
                            value={travelDate}
                            min={today}
                            onChange={e => setTravelDate(e.target.value)}
                            required
                            className="input-field pl-9 pt-5 pb-1.5 h-14 text-sm w-full"
                        />
                    </div>

                    {/* Passengers — always present */}
                    <FieldSelect
                        label="Passengers"
                        icon={Users}
                        iconColor="text-amber-500 dark:text-amber-400"
                        value={passengers}
                        onChange={setPassengers}
                        options={PASSENGERS.map(p => ({ id: String(p), label: `${p} ${p === 1 ? 'Adult' : 'Adults'}` }))}
                    />

                    {/* Class — flight/train/bus specific */}
                    {mode !== 'COMBINED' && (
                        <FieldSelect
                            label={mode === 'FLIGHT' ? 'Cabin Class' : mode === 'TRAIN' ? 'Coach Type' : 'Seat Type'}
                            value={seatClass}
                            onChange={setSeatClass}
                            options={classOptions()}
                        />
                    )}

                    {/* Sort Mode — only for Combined */}
                    {mode === 'COMBINED' && (
                        <>
                            <FieldSelect
                                label="Cabin"
                                value={seatClass}
                                onChange={setSeatClass}
                                options={FLIGHT_CLASSES}
                            />
                            <FieldSelect
                                label="Sort by"
                                value={optimizationMode}
                                onChange={setOptimizationMode}
                                options={COMBINED_MODES}
                            />
                        </>
                    )}
                </div>

                {/* ── SEARCH BUTTON ── */}
                <button
                    type="submit"
                    className="btn-primary w-full flex items-center justify-center gap-2 text-lg font-bold py-4 rounded-xl group hover:-translate-y-0.5 shadow-xl shadow-primary-500/25 mt-2"
                >
                    <Search className="w-5 h-5 group-hover:rotate-12 transition-transform duration-200" />
                    {mode === 'COMBINED' ? 'Search All Routes' : `Search ${MODES.find(m => m.id === mode)?.label}`}
                </button>
            </form>
        </div>
    )
}

import { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { MapPin, TrendingUp, ChevronRight, Plane, Train, Bus } from 'lucide-react'
import { searchApi } from '../api/axios'

const STATIC_ROUTES = [
    { origin: 'Ahmedabad', destination: 'Mumbai', modes: ['BUS', 'TRAIN'], bookings: 1240, price: '₹800' },
    { origin: 'Delhi', destination: 'Srinagar', modes: ['TRAIN', 'FLIGHT'], bookings: 980, price: '₹3,200' },
    { origin: 'Mumbai', destination: 'Delhi', modes: ['FLIGHT'], bookings: 1860, price: '₹4,500' },
    { origin: 'Ahmedabad', destination: 'Srinagar', modes: ['BUS', 'FLIGHT'], bookings: 720, price: '₹5,100' },
    { origin: 'Delhi', destination: 'Jaipur', modes: ['BUS', 'TRAIN'], bookings: 2100, price: '₹450' },
    { origin: 'Pune', destination: 'Delhi', modes: ['TRAIN', 'FLIGHT'], bookings: 850, price: '₹3,800' },
    { origin: 'Bangalore', destination: 'Mumbai', modes: ['FLIGHT'], bookings: 1500, price: '₹2,800' },
    { origin: 'Chennai', destination: 'Hyderabad', modes: ['TRAIN', 'BUS'], bookings: 1100, price: '₹600' },
]

const ModeIcon = ({ mode }) => {
    if (mode === 'FLIGHT') return <Plane className="w-3 h-3 text-sky-400" />
    if (mode === 'TRAIN') return <Train className="w-3 h-3 text-emerald-400" />
    return <Bus className="w-3 h-3 text-amber-400" />
}

const modeColor = {
    FLIGHT: 'text-sky-400 bg-sky-500/10 border-sky-500/20',
    TRAIN: 'text-emerald-400 bg-emerald-500/10 border-emerald-500/20',
    BUS: 'text-amber-400 bg-amber-500/10 border-amber-500/20',
}

export default function PopularRoutes() {
    const navigate = useNavigate()
    const [routes, setRoutes] = useState(STATIC_ROUTES)

    const handleClick = (route) => {
        navigate('/search', {
            state: {
                searchParams: {
                    originCity: route.origin,
                    destinationCity: route.destination,
                    travelDate: new Date().toISOString().split('T')[0],
                    optimizationMode: 'BALANCED',
                }
            }
        })
    }

    return (
        <section className="py-4 px-4">
            <div className="max-w-7xl mx-auto">
                <div className="flex items-center justify-between mb-8">
                    <div>
                        <h2 className="text-2xl font-bold text-gray-900 dark:text-white flex items-center gap-2">
                            <TrendingUp className="w-5 h-5 text-primary-400" />
                            Popular Routes
                        </h2>
                        <p className="text-gray-500 text-sm mt-1">Most booked journeys on Tripline</p>
                    </div>
                </div>

                <div className="grid sm:grid-cols-2 lg:grid-cols-4 gap-4">
                    {routes.map((r, i) => (
                        <button
                            key={i}
                            onClick={() => handleClick(r)}
                            className="glass-card bg-white/60 dark:bg-dark-800/60 p-5 text-left hover:border-primary-500/30 dark:hover:border-primary-500/30 hover:bg-white/80 dark:hover:bg-dark-700/80 transition-all duration-300 group hover:-translate-y-1.5 hover:shadow-xl hover:shadow-primary-600/10"
                        >
                            {/* Route rank */}
                            <div className="flex items-center justify-between mb-3">
                                <span className="text-[10px] font-black text-gray-700 dark:text-gray-300 bg-gray-200/50 dark:bg-dark-600 px-2.5 py-1 rounded-full border border-gray-300/50 dark:border-white/5">
                                    #{i + 1} Popular
                                </span>
                                <ChevronRight className="w-4 h-4 text-gray-600 group-hover:text-primary-400 group-hover:translate-x-0.5 transition-all" />
                            </div>

                            {/* Route */}
                            <div className="flex items-center gap-1.5 text-base font-bold text-gray-900 dark:text-white group-hover:text-primary-500 transition-colors mb-2">
                                <span>{r.origin}</span>
                                <div className="flex items-center gap-0.5 text-gray-600">
                                    <div className="w-4 h-px bg-gray-700" />
                                    <MapPin className="w-3 h-3" />
                                    <div className="w-4 h-px bg-gray-700" />
                                </div>
                                <span>{r.destination}</span>
                            </div>

                            {/* Modes */}
                            <div className="flex items-center gap-1.5 mb-3">
                                {r.modes.map((m, j) => (
                                    <span key={j} className={`inline-flex items-center gap-1 text-[11px] font-semibold px-2 py-0.5 rounded-full border ${modeColor[m]}`}>
                                        <ModeIcon mode={m} />
                                        {m.charAt(0) + m.slice(1).toLowerCase()}
                                    </span>
                                ))}
                            </div>

                            {/* Price + bookings */}
                            <div className="flex items-center justify-between">
                                <span className="text-primary-600 dark:text-primary-400 font-bold text-sm">From {r.price}</span>
                                <span className="text-gray-500 dark:text-gray-500 text-[11px]">{r.bookings.toLocaleString()} trips</span>
                            </div>
                        </button>
                    ))}
                </div>
            </div>
        </section>
    )
}

import { useState, useEffect, useRef } from 'react'
import { useNavigate } from 'react-router-dom'
import { Search, MapPin, Calendar, Zap, TrendingDown, Clock, ArrowRight } from 'lucide-react'
import { stationApi } from '../api/axios'
import DatePicker from 'react-datepicker'
import 'react-datepicker/dist/react-datepicker.css'

function CityInput({ label, value, onChange, placeholder, icon, availableCities = [] }) {
    const [show, setShow] = useState(false)
    const ref = useRef(null)

    const suggestions = availableCities.filter(c => c.toLowerCase().includes((value || '').toLowerCase()))

    useEffect(() => {
        const handleClick = (e) => { if (ref.current && !ref.current.contains(e.target)) setShow(false) }
        document.addEventListener('mousedown', handleClick)
        return () => document.removeEventListener('mousedown', handleClick)
    }, [])

    return (
        <div className="relative flex-1" ref={ref}>
            <label className="block text-xs text-gray-500 uppercase tracking-wider mb-1.5 font-semibold">{label}</label>
            <div className="relative">
                <MapPin className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-500" />
                <input
                    type="text"
                    value={value}
                    onChange={e => { onChange(e.target.value); setShow(true); }}
                    placeholder={placeholder}
                    className="input-field pl-9 w-full cursor-pointer text-gray-900 dark:text-white"
                    onFocus={() => setShow(true)}
                    autoComplete="off"
                />
            </div>
            {show && suggestions.length > 0 && (
                <ul className="absolute top-full mt-2 left-0 right-0 bg-white dark:bg-dark-700 border border-gray-200 dark:border-white/10 rounded-xl overflow-hidden z-50 shadow-2xl animate-fade-in max-h-60 overflow-y-auto custom-scrollbar">
                    {suggestions.map(city => (
                        <li
                            key={city}
                            className="flex items-center gap-2 px-4 py-3 hover:bg-gray-50 dark:hover:bg-dark-600 cursor-pointer transition-colors text-sm text-gray-800 dark:text-white"
                            onMouseDown={(e) => { e.preventDefault(); onChange(city); setShow(false); }}
                        >
                            <MapPin className="w-3.5 h-3.5 text-primary-400" />
                            {city}
                        </li>
                    ))}
                </ul>
            )}
        </div>
    )
}

const MODES = [
    { value: 'BALANCED', label: 'Balanced', icon: <Zap className="w-3.5 h-3.5" /> },
    { value: 'CHEAPEST', label: 'Cheapest', icon: <TrendingDown className="w-3.5 h-3.5" /> },
    { value: 'FASTEST', label: 'Fastest', icon: <Clock className="w-3.5 h-3.5" /> },
]

export default function SearchBar({ initialValues, onSearch, loading = false }) {
    const navigate = useNavigate()
    const [origin, setOrigin] = useState(initialValues?.originCity || '')
    const [destination, setDestination] = useState(initialValues?.destinationCity || '')
    const [date, setDate] = useState(initialValues?.travelDate ? new Date(initialValues.travelDate) : new Date())
    const [mode, setMode] = useState(initialValues?.optimizationMode || 'BALANCED')
    const [availableCities, setAvailableCities] = useState([])

    useEffect(() => {
        stationApi.getCities().then(res => setAvailableCities(res.data)).catch(console.error)
    }, [])

    const handleSubmit = (e) => {
        e.preventDefault()
        if (!date) return

        const params = {
            originCity: origin,
            destinationCity: destination,
            travelDate: date.toISOString().split('T')[0],
            optimizationMode: mode
        }

        if (onSearch) {
            onSearch(params)
        } else {
            navigate('/search', { state: { searchParams: params } })
        }
    }

    const swapCities = () => {
        const tmp = origin
        setOrigin(destination)
        setDestination(tmp)
    }

    return (
        <form onSubmit={handleSubmit} className="glass-card p-6">
            {/* Mode Selector */}
            <div className="flex gap-2 mb-5">
                {MODES.map(m => (
                    <button
                        key={m.value}
                        type="button"
                        onClick={() => setMode(m.value)}
                        className={`flex items-center gap-1.5 text-xs font-semibold px-4 py-2 rounded-lg transition-all ${mode === m.value
                            ? 'bg-primary-600 text-white shadow-lg shadow-primary-600/25'
                            : 'bg-white dark:bg-dark-700 text-gray-500 dark:text-gray-400 hover:text-gray-900 dark:hover:text-white border border-gray-200 dark:border-white/5'
                            }`}
                    >
                        {m.icon}{m.label}
                    </button>
                ))}
            </div>

            <div className="flex flex-col lg:flex-row gap-3 items-end">
                {/* Origin */}
                <CityInput label="From" value={origin} onChange={setOrigin} placeholder="Origin city" availableCities={availableCities} />

                {/* Swap Button */}
                <button
                    type="button"
                    onClick={swapCities}
                    className="hidden lg:flex items-center justify-center w-10 h-10 mb-0.5 rounded-full border border-gray-200 dark:border-white/10 text-gray-500 dark:text-gray-400 hover:text-primary-600 dark:hover:text-white hover:border-primary-500 transition-all flex-shrink-0 bg-white dark:bg-transparent"
                >
                    <ArrowRight className="w-4 h-4" />
                </button>

                {/* Destination */}
                <CityInput label="To" value={destination} onChange={setDestination} placeholder="Destination city" availableCities={availableCities} />

                {/* Date */}
                <div className="flex-1 min-w-[160px]">
                    <label className="block text-xs text-gray-500 uppercase tracking-wider mb-1.5 font-semibold">Date</label>
                    <div className="relative">
                        <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-500 z-10 pointer-events-none" />
                        <DatePicker
                            selected={date}
                            onChange={setDate}
                            minDate={new Date()}
                            dateFormat="dd MMM yyyy"
                            className="input-field pl-9 w-full"
                            wrapperClassName="w-full"
                        />
                    </div>
                </div>

                {/* Search Button */}
                <button
                    type="submit"
                    disabled={loading}
                    className="btn-primary h-[46px] px-8 flex items-center gap-2 flex-shrink-0"
                >
                    {loading ? (
                        <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
                    ) : (
                        <Search className="w-4 h-4" />
                    )}
                    {loading ? 'Searching...' : 'Search'}
                </button>
            </div>
        </form>
    )
}

/**
 * SeatMapTrain — Renders a train coach berth layout.
 * groups seats into compartments of 8 and shows berth type labels.
 */
export default function SeatMapTrain({ seats = [], selectedSeats = new Set(), onSeatClick, lockedByOthers = new Set() }) {
    if (seats.length === 0) {
        return <div className="text-gray-500 text-sm py-8 text-center">Select a coach to view seats</div>
    }

    const berthLabel = { L: 'Lower', M: 'Middle', U: 'Upper', SL: 'Side Lower', SU: 'Side Upper' }
    const berthOrder = ['L', 'M', 'U', 'SL', 'SU']

    // Split seats into 8-seat compartments (6 main + 2 side)
    const mainSeats = seats.filter(s => !['SL', 'SU'].includes(s.berthType))
    const sideSeats = seats.filter(s => ['SL', 'SU'].includes(s.berthType))

    // Group main seats into compartments of 6
    const COMP_SIZE = 6
    const compartments = []
    for (let i = 0; i < mainSeats.length; i += COMP_SIZE) {
        compartments.push(mainSeats.slice(i, i + COMP_SIZE))
    }
    // Group side seats into 2 per "side unit"
    const SIDE_SIZE = 2
    const sideUnits = []
    for (let i = 0; i < sideSeats.length; i += SIDE_SIZE) {
        sideUnits.push(sideSeats.slice(i, i + SIDE_SIZE))
    }

    const getSeatStyle = (seat) => {
        const seatNo = seat.seatNo
        if (selectedSeats.has(seatNo)) return 'bg-emerald-500/40 border-emerald-400 text-emerald-200 cursor-pointer'
        if (lockedByOthers.has(seatNo) || seat.status === 'LOCKED') return 'bg-blue-500/25 border-blue-400/60 text-blue-300 cursor-not-allowed'
        if (seat.status === 'BOOKED') return 'bg-gray-700/60 border-gray-600 text-gray-500 cursor-not-allowed'
        return 'bg-white/8 border-white/20 text-gray-300 cursor-pointer hover:border-primary-500 hover:bg-primary-500/20 transition-all'
    }

    const berthColor = {
        L: 'text-green-400', M: 'text-yellow-400', U: 'text-blue-400',
        SL: 'text-orange-400', SU: 'text-pink-400'
    }

    const renderSeat = (seat) => (
        <button
            key={seat.seatNo}
            type="button"
            disabled={seat.status === 'BOOKED' || (seat.status === 'LOCKED' && !selectedSeats.has(seat.seatNo))}
            onClick={() => onSeatClick?.(seat)}
            title={`Seat ${seat.seatNo} | ${berthLabel[seat.berthType] || seat.berthType} | ${seat.seatClass} | ₹${seat.price}`}
            className={`flex flex-col items-center justify-center rounded border px-2 py-1.5 text-xs font-bold transition-all ${getSeatStyle(seat)}`}
        >
            <span className="font-mono text-sm">{seat.seatNo}</span>
            <span className={`text-[10px] font-normal ${berthColor[seat.berthType] || 'text-gray-400'}`}>
                {berthLabel[seat.berthType] || seat.berthType}
            </span>
        </button>
    )

    return (
        <div className="space-y-6">
            {/* Side berths legend */}
            <div className="flex gap-2 flex-wrap">
                {berthOrder.map(b => (
                    <span key={b} className={`text-[11px] px-2 py-0.5 rounded border border-white/10 bg-white/5 ${berthColor[b]}`}>
                        {b} = {berthLabel[b]}
                    </span>
                ))}
            </div>

            {compartments.map((comp, ci) => {
                const lowerRow = comp.filter(s => s.berthType === 'L' || s.berthType === 'M')
                const upperRow = comp.filter(s => s.berthType === 'U')
                const sideUnit = sideUnits[ci]

                return (
                    <div key={ci} className="border border-white/10 rounded-xl p-4 bg-white/3">
                        <div className="text-xs text-gray-500 mb-2 font-semibold">
                            Compartment {ci + 1} — Seats {comp[0]?.seatNo}–{comp[comp.length - 1]?.seatNo}
                        </div>
                        <div className="flex gap-4">
                            {/* Main berths */}
                            <div className="flex-1 space-y-2">
                                <div className="text-[10px] text-gray-600 uppercase tracking-wider">Lower / Middle</div>
                                <div className="flex gap-2 flex-wrap">
                                    {comp.filter(s => ['L', 'M'].includes(s.berthType)).map(renderSeat)}
                                </div>
                                <div className="text-[10px] text-gray-600 uppercase tracking-wider mt-2">Upper</div>
                                <div className="flex gap-2 flex-wrap">
                                    {comp.filter(s => s.berthType === 'U').map(renderSeat)}
                                </div>
                            </div>

                            {/* Side berths */}
                            {sideUnit && sideUnit.length > 0 && (
                                <div className="border-l border-white/10 pl-4 min-w-16">
                                    <div className="text-[10px] text-gray-600 uppercase tracking-wider mb-2">Side</div>
                                    <div className="flex flex-col gap-2">
                                        {sideUnit.map(renderSeat)}
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>
                )
            })}
        </div>
    )
}

import { createContext, useContext, useEffect, useState } from 'react'
import { authApi } from '../api/axios'

const AuthContext = createContext(null)

export function AuthProvider({ children }) {
    const [user, setUser] = useState(null)
    const [loading, setLoading] = useState(true)

    // On mount, try to fetch the current user from the cookie
    useEffect(() => {
        authApi.getMe()
            .then(res => setUser(res.data))
            .catch(() => setUser(null))
            .finally(() => setLoading(false))
    }, [])

    const login = async (credentials) => {
        const res = await authApi.login(credentials)
        setUser(res.data)
        return res.data
    }

    const register = async (data) => {
        const res = await authApi.register(data)
        // Don't set user yet; verification required
        return res.data
    }

    const verifyEmail = async (data) => {
        const res = await authApi.verifyEmail(data)
        setUser(res.data)
        return res.data
    }

    const logout = async () => {
        await authApi.logout()
        setUser(null)
    }

    const updateProfile = async (data) => {
        const res = await authApi.updateProfile(data)
        setUser(res.data)
        return res.data
    }

    const isAdmin = user?.role === 'ADMIN'
    const isAuthenticated = !!user

    return (
        <AuthContext.Provider value={{ user, loading, isAuthenticated, isAdmin, login, register, verifyEmail, logout, updateProfile }}>
            {children}
        </AuthContext.Provider>
    )
}

export function useAuth() {
    const ctx = useContext(AuthContext)
    if (!ctx) throw new Error('useAuth must be used inside AuthProvider')
    return ctx
}

import { useState, useCallback } from 'react'
import { useLocation, useNavigate } from 'react-router-dom'
import { bookingApi, paymentApi, seatApi } from '../api/axios'
import { useAuth } from '../context/AuthContext'
import JourneyTimeline from '../components/JourneyTimeline'
import SeatMapFlight from '../components/SeatMapFlight'
import SeatMapBus from '../components/SeatMapBus'
import SeatMapTrain from '../components/SeatMapTrain'
import SeatLegend from '../components/SeatLegend'
import SeatTimer from '../components/SeatTimer'
import CoachSelector from '../components/CoachSelector'
import PassengerSeatMapper from '../components/PassengerSeatMapper'
import toast from 'react-hot-toast'
import { User, Plus, Trash2, CreditCard, MapPin, ChevronRight, ChevronLeft } from 'lucide-react'

const emptyPassenger = () => ({ name: '', age: '', gender: 'MALE' })

// Steps: 0 = Passengers, 1 = Seats, 2 = Review & Pay
const STEPS = ['Passengers', 'Select Seats', 'Review & Pay']

export default function BookingPage() {
    const { state } = useLocation()
    const navigate = useNavigate()
    const { user, token } = useAuth()
    const route = state?.route

    const [step, setStep] = useState(0)
    const [passengers, setPassengers] = useState([{ ...emptyPassenger(), name: user?.name || '' }])
    const [loading, setLoading] = useState(false)

    // Seat selection state (per leg)
    const [currentLegIdx, setCurrentLegIdx] = useState(0)
    const [seatMaps, setSeatMaps] = useState({}) // tripId -> { seats, coaches, mode, ... }
    const [selectedCoach, setSelectedCoach] = useState({}) // tripId -> coachNo
    const [coachSeats, setCoachSeats] = useState({}) // "tripId:coachNo" -> seats[]
    // seatAssignments: { legIdx: { passengerIdx: seatObject } }
    const [seatAssignments, setSeatAssignments] = useState({})
    const [pendingPassengerIdx, setPendingPassengerIdx] = useState(0)
    const [lockedSeats, setLockedSeats] = useState({}) // seatNo -> true (locked by us)
    const [lockTimerStarted, setLockTimerStarted] = useState(false)
    const [seatMapLoading, setSeatMapLoading] = useState(false)

    if (!route) { navigate('/search'); return null }

    const legs = route.legs || []
    const tripIds = legs.map(l => l.tripId)

    // ----------------------------------------------------------------
    // Passenger form helpers
    // ----------------------------------------------------------------
    const addPassenger = () => {
        if (passengers.length >= (legs[0]?.availableSeats || 9)) {
            toast.error('Max passengers reached for this route'); return
        }
        setPassengers(p => [...p, emptyPassenger()])
    }
    const removePassenger = (i) => {
        if (passengers.length <= 1) return
        setPassengers(p => p.filter((_, idx) => idx !== i))
        // Also remove their seat assignments
        setSeatAssignments(prev => {
            const newA = { ...prev }
            for (const li in newA) {
                const legAssignments = { ...newA[li] }
                delete legAssignments[i]
                newA[li] = legAssignments
            }
            return newA
        })
    }
    const setField = (i, key, val) =>
        setPassengers(p => p.map((p2, idx) => idx === i ? { ...p2, [key]: val } : p2))

    const validatePassengers = () => {
        for (const p of passengers) {
            if (!p.name.trim()) { toast.error('Please enter all passenger names'); return false }
        }
        return true
    }

    // ----------------------------------------------------------------
    // Seat map loading
    // ----------------------------------------------------------------
    const loadSeatMap = async (tripId) => {
        if (seatMaps[tripId]) return // already loaded
        setSeatMapLoading(true)
        try {
            const res = await seatApi.getSeatMap(tripId)
            setSeatMaps(prev => ({ ...prev, [tripId]: res.data }))
        } catch (err) {
            toast.error('Failed to load seat map: ' + (err.response?.data?.message || err.message))
            setSeatMaps(prev => ({ ...prev, [tripId]: { _loaded: true } }))
        } finally {
            setSeatMapLoading(false)
        }
    }

    const loadCoachSeats = async (tripId, coachNo) => {
        const key = `${tripId}:${coachNo}`
        if (coachSeats[key]) return
        try {
            const res = await seatApi.getCoachSeats(tripId, coachNo)
            setCoachSeats(prev => ({ ...prev, [key]: res.data }))
        } catch {
            toast.error('Failed to load coach seats')
        }
    }

    const handleCoachSelect = (tripId, coachNo) => {
        setSelectedCoach(prev => ({ ...prev, [tripId]: coachNo }))
        loadCoachSeats(tripId, coachNo)
    }

    // ----------------------------------------------------------------
    // Seat selection
    // ----------------------------------------------------------------
    const getCurrentLegTripId = () => legs[currentLegIdx]?.tripId
    // transportMode from the leg (API returns 'transportMode' not 'mode')
    const getCurrentTransportMode = () =>
        legs[currentLegIdx]?.transportMode || seatMaps[legs[currentLegIdx]?.tripId]?.transportMode

    const isAlreadySelected = (seatNo) => {
        const legAssignments = seatAssignments[currentLegIdx] || {}
        return Object.values(legAssignments).some(s => s.seatNo === seatNo)
    }

    const getSelectedSeatNos = () => {
        const legAssignments = seatAssignments[currentLegIdx] || {}
        return new Set(Object.values(legAssignments).map(s => s.seatNo))
    }

    const handleSeatClick = useCallback(async (seat) => {
        const tripId = getCurrentLegTripId()
        const mode = getCurrentTransportMode()

        // For trains: seatNo in API must be "coachNo:seatNo" composite
        const lockKey = (mode === 'TRAIN' && seat.coachNo)
            ? `${seat.coachNo}:${seat.seatNo}`
            : seat.seatNo

        // Check if this passenger already has a seat
        const legAssignments = seatAssignments[currentLegIdx] || {}
        if (legAssignments[pendingPassengerIdx]) {
            // Unlock old seat first (using the stored lockKey)
            const oldSeat = legAssignments[pendingPassengerIdx]
            const oldLockKey = oldSeat._lockKey || oldSeat.seatNo
            await handleUnlockSeat(tripId, oldLockKey, mode)
        }

        // Lock the new seat via API
        const locked = await handleLockSeat(tripId, lockKey, mode)
        if (!locked) return

        setSeatAssignments(prev => ({
            ...prev,
            [currentLegIdx]: {
                ...(prev[currentLegIdx] || {}),
                [pendingPassengerIdx]: { ...seat, _lockKey: lockKey }
            }
        }))

        if (!lockTimerStarted) setLockTimerStarted(true)

        // Move to next unassigned passenger
        const nextUnassigned = passengers.findIndex((_, i) =>
            i !== pendingPassengerIdx && !((seatAssignments[currentLegIdx] || {})[i])
        )
        if (nextUnassigned !== -1) setPendingPassengerIdx(nextUnassigned)
    }, [currentLegIdx, pendingPassengerIdx, passengers, seatAssignments, lockTimerStarted])

    const handleRemoveSeat = async (passengerIdx) => {
        const tripId = getCurrentLegTripId()
        const mode = getCurrentTransportMode()
        const seat = (seatAssignments[currentLegIdx] || {})[passengerIdx]
        if (seat) {
            const lockKey = seat._lockKey || seat.seatNo
            await handleUnlockSeat(tripId, lockKey, mode)
            setSeatAssignments(prev => {
                const legAssignments = { ...(prev[currentLegIdx] || {}) }
                delete legAssignments[passengerIdx]
                return { ...prev, [currentLegIdx]: legAssignments }
            })
        }
        setPendingPassengerIdx(passengerIdx)
    }

    const handleLockSeat = async (tripId, seatNo, mode) => {
        try {
            const res = await seatApi.lockSeat(tripId, seatNo)
            if (res.data.locked) {
                setLockedSeats(prev => ({ ...prev, [seatNo]: true }))
                return true
            } else {
                toast.error(res.data.message || 'Seat already taken')
                return false
            }
        } catch (err) {
            toast.error(err.response?.data?.message || 'Could not lock seat')
            return false
        }
    }

    const handleUnlockSeat = async (tripId, seatNo, mode) => {
        try {
            await seatApi.unlockSeat(tripId, seatNo)
            setLockedSeats(prev => { const n = { ...prev }; delete n[seatNo]; return n })
        } catch { /* silent */ }
    }

    const allSeatsAssigned = () => {
        for (let li = 0; li < legs.length; li++) {
            const assignments = seatAssignments[li] || {}
            if (Object.keys(assignments).length < passengers.length) return false
        }
        return true
    }

    // ----------------------------------------------------------------
    // Final booking
    // ----------------------------------------------------------------
    const handleBook = async () => {
        setLoading(true)
        try {
            const passengersPayload = passengers.map((p, i) => {
                // Gather seat data for first leg (multi-leg uses same passenger across legs)
                const firstLegSeat = (seatAssignments[0] || {})[i]
                return {
                    name: p.name,
                    email: user?.email,
                    phone: p.phone || null,
                    seatNumber: firstLegSeat?.seatNo || null,
                    coachNumber: firstLegSeat?.coachNo || null,
                    seatClass: firstLegSeat?.seatClass || null,
                    berthType: firstLegSeat?.berthType || null,
                }
            })

            // For multi-leg, build per-leg passengers
            const legsPassengers = tripIds.map((tripId, li) =>
                passengers.map((p, i) => {
                    const seat = (seatAssignments[li] || {})[i]
                    return {
                        name: p.name,
                        email: user?.email,
                        phone: p.phone || null,
                        seatNumber: seat?.seatNo || null,
                        coachNumber: seat?.coachNo || null,
                        seatClass: seat?.seatClass || null,
                        berthType: seat?.berthType || null,
                    }
                })
            )

            // Flatten passengers matching number of tripIds (one passenger per leg-passenger pair)
            const flatPassengers = []
            for (let li = 0; li < tripIds.length; li++) {
                for (let pi = 0; pi < passengers.length; pi++) {
                    const seat = (seatAssignments[li] || {})[pi]
                    flatPassengers.push({
                        name: passengers[pi].name,
                        email: user?.email,
                        seatNumber: seat?.seatNo || null,
                        coachNumber: seat?.coachNo || null,
                        seatClass: seat?.seatClass || null,
                        berthType: seat?.berthType || null,
                    })
                }
            }

            const bookingRes = await bookingApi.create({
                tripIds,
                passengers: passengersPayload
            })
            const bookingId = bookingRes.data.bookingId
            const sessionRes = await paymentApi.createSession({ bookingId })
            window.location.href = sessionRes.data.sessionUrl
        } catch (err) {
            toast.error(err.response?.data?.message || 'Booking failed. Please try again.')
            setLoading(false)
        }
    }

    const handleTimerExpire = async () => {
        toast.error('Your seat locks have expired. Please reselect seats.')
        setSeatAssignments({})
        setLockedSeats({})
        setLockTimerStarted(false)
        setStep(1)
        // Reload seat maps
        setSeatMaps({})
        setCoachSeats({})
    }

    // ----------------------------------------------------------------
    // Step navigation
    // ----------------------------------------------------------------
    const goToStep = async (nextStep) => {
        if (nextStep === 1) {
            if (!validatePassengers()) return
            // Load first leg seat map
            const firstTripId = legs[0]?.tripId
            if (firstTripId) await loadSeatMap(firstTripId)
        }
        setStep(nextStep)
    }

    // ----------------------------------------------------------------
    // Render
    // ----------------------------------------------------------------
    const currentTripId = getCurrentLegTripId()
    const currentSeatMap = seatMaps[currentTripId] || {}
    const transportMode = getCurrentTransportMode()
    const currentCoach = selectedCoach[currentTripId]
    const currentCoachSeats = coachSeats[`${currentTripId}:${currentCoach}`] || []
    const selectedSeatNos = getSelectedSeatNos()

    // Calculate total — use seat prices if available
    const totalPrice = (() => {
        let total = 0
        for (let pi = 0; pi < passengers.length; pi++) {
            const firstLegSeat = (seatAssignments[0] || {})[pi]
            if (firstLegSeat?.price) {
                total += Number(firstLegSeat.price) * legs.length
            } else {
                total += Number(route.totalPrice)
            }
        }
        return total
    })()

    return (
        <div className="min-h-screen pt-20 pb-16 px-4">
            <div className="max-w-6xl mx-auto">

                {/* Step indicator */}
                <div className="mb-8 animate-slide-up">
                    <h1 className="text-3xl font-bold text-white mb-4">Complete Booking</h1>
                    <div className="flex items-center gap-2">
                        {STEPS.map((s, i) => (
                            <div key={i} className="flex items-center">
                                <div className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-sm font-semibold transition-all
                  ${step === i ? 'bg-primary-600 text-white' : step > i ? 'bg-emerald-600/30 text-emerald-400' : 'bg-white/5 text-gray-500'}`}>
                                    <span className={`w-5 h-5 rounded-full flex items-center justify-center text-xs
                    ${step === i ? 'bg-white text-primary-600' : step > i ? 'bg-emerald-500 text-white' : 'bg-white/10 text-gray-500'}`}>
                                        {step > i ? '✓' : i + 1}
                                    </span>
                                    {s}
                                </div>
                                {i < STEPS.length - 1 && <ChevronRight className="w-4 h-4 text-gray-600 mx-1" />}
                            </div>
                        ))}
                    </div>
                </div>

                <div className="grid lg:grid-cols-3 gap-8">

                    {/* Main content */}
                    <div className="lg:col-span-2">

                        {/* STEP 0: Passengers */}
                        {step === 0 && (
                            <div className="space-y-6 animate-fade-in">
                                {passengers.map((p, i) => (
                                    <div key={i} className="glass-card p-6">
                                        <div className="flex items-center justify-between mb-4">
                                            <div className="flex items-center gap-2">
                                                <div className="w-8 h-8 bg-primary-600/20 border border-primary-500/30 rounded-full flex items-center justify-center">
                                                    <User className="w-4 h-4 text-primary-400" />
                                                </div>
                                                <h3 className="text-white font-semibold">Passenger {i + 1}</h3>
                                            </div>
                                            {i > 0 && (
                                                <button type="button" onClick={() => removePassenger(i)}
                                                    className="text-red-400 hover:text-red-300 p-1 transition-colors">
                                                    <Trash2 className="w-4 h-4" />
                                                </button>
                                            )}
                                        </div>
                                        <div className="grid sm:grid-cols-3 gap-4">
                                            <div className="sm:col-span-1">
                                                <label className="block text-xs text-gray-500 uppercase tracking-wider mb-1.5 font-semibold">Full Name</label>
                                                <input type="text" required value={p.name}
                                                    onChange={e => setField(i, 'name', e.target.value)}
                                                    className="input-field" placeholder="Full name" />
                                            </div>
                                            <div>
                                                <label className="block text-xs text-gray-500 uppercase tracking-wider mb-1.5 font-semibold">Age</label>
                                                <input type="number" min="1" max="120" value={p.age || ''}
                                                    onChange={e => setField(i, 'age', e.target.value)}
                                                    className="input-field" placeholder="Age" />
                                            </div>
                                            <div>
                                                <label className="block text-xs text-gray-500 uppercase tracking-wider mb-1.5 font-semibold">Gender</label>
                                                <select value={p.gender} onChange={e => setField(i, 'gender', e.target.value)} className="input-field">
                                                    <option value="MALE">Male</option>
                                                    <option value="FEMALE">Female</option>
                                                    <option value="OTHER">Other</option>
                                                </select>
                                            </div>
                                        </div>
                                    </div>
                                ))}

                                <button type="button" onClick={addPassenger}
                                    className="flex items-center gap-2 text-primary-400 hover:text-primary-300 text-sm font-medium transition-colors">
                                    <Plus className="w-4 h-4" /> Add Passenger
                                </button>

                                <button onClick={() => goToStep(1)}
                                    className="btn-primary w-full flex items-center justify-center gap-2 text-base py-4">
                                    Continue to Seat Selection <ChevronRight className="w-5 h-5" />
                                </button>
                            </div>
                        )}

                        {/* STEP 1: Seat Selection */}
                        {step === 1 && (
                            <div className="animate-fade-in space-y-6">
                                {/* Lock timer */}
                                {lockTimerStarted && (
                                    <SeatTimer initialSeconds={300} onExpire={handleTimerExpire} />
                                )}

                                {/* Leg selector (for multi-leg) */}
                                {legs.length > 1 && (
                                    <div className="flex gap-2 flex-wrap">
                                        {legs.map((leg, li) => (
                                            <button key={li} type="button"
                                                onClick={async () => {
                                                    setCurrentLegIdx(li)
                                                    setPendingPassengerIdx(0)
                                                    if (leg.tripId) await loadSeatMap(leg.tripId)
                                                }}
                                                className={`px-4 py-2 rounded-lg text-sm font-semibold border transition-all
                          ${currentLegIdx === li ? 'bg-primary-600 border-primary-500 text-white' : 'bg-white/5 border-white/15 text-gray-300 hover:border-white/30'}`}>
                                                Leg {li + 1}: {leg.origin} → {leg.destination}
                                            </button>
                                        ))}
                                    </div>
                                )}

                                {/* Passenger ↔ Seat mapper */}
                                <div className="glass-card p-5">
                                    <h3 className="text-white font-semibold mb-3 flex items-center gap-2">
                                        <MapPin className="w-4 h-4 text-primary-400" />
                                        Passenger → Seat Assignment
                                    </h3>
                                    <PassengerSeatMapper
                                        passengers={passengers}
                                        seatAssignments={seatAssignments[currentLegIdx] || {}}
                                        onRemoveSeat={handleRemoveSeat}
                                        pendingSeatIndex={pendingPassengerIdx}
                                        onSetPending={setPendingPassengerIdx}
                                    />
                                </div>

                                {/* Seat map */}
                                <div className="glass-card p-5 overflow-auto">
                                    <h3 className="text-white font-semibold mb-4">
                                        Seat Map — {legs[currentLegIdx]?.origin} → {legs[currentLegIdx]?.destination}
                                        {transportMode && <span className="ml-2 text-xs text-gray-500 bg-white/10 px-2 py-0.5 rounded">{transportMode}</span>}
                                    </h3>

                                    {/* Train coach selector */}
                                    {transportMode === 'TRAIN' && currentSeatMap.coaches && (
                                        <div className="mb-4">
                                            <p className="text-xs text-gray-500 mb-2">Select Coach:</p>
                                            <CoachSelector
                                                coaches={currentSeatMap.coaches}
                                                selectedCoach={currentCoach}
                                                onSelect={(coachNo) => handleCoachSelect(currentTripId, coachNo)}
                                            />
                                        </div>
                                    )}

                                    {/* Class availability pills — shown above the map */}
                                    {currentSeatMap.availability && Object.keys(currentSeatMap.availability).length > 0 && (
                                        <div className="mb-4 flex flex-wrap gap-2">
                                            <span className="text-xs text-gray-500 self-center font-semibold uppercase tracking-wider">Availability:</span>
                                            {Object.entries(currentSeatMap.availability).map(([cls, count]) => {
                                                const price = currentSeatMap.classPrices?.[cls]
                                                const isLow = count <= 5
                                                const isMed = count > 5 && count <= 20
                                                return (
                                                    <div key={cls} className={`flex flex-col items-center px-3 py-1.5 rounded-lg border text-center
                                                        ${isLow ? 'bg-red-500/10 border-red-500/30' : isMed ? 'bg-amber-500/10 border-amber-500/30' : 'bg-emerald-500/10 border-emerald-500/30'}`}>
                                                        <span className="text-[10px] font-bold text-gray-400 uppercase tracking-wider">{cls}</span>
                                                        <span className={`text-sm font-bold ${isLow ? 'text-red-400' : isMed ? 'text-amber-400' : 'text-emerald-400'}`}>{count} left</span>
                                                        {price && <span className="text-[10px] text-gray-500">₹{Number(price).toLocaleString('en-IN')}</span>}
                                                    </div>
                                                )
                                            })}
                                        </div>
                                    )}

                                    {transportMode === 'FLIGHT' && currentSeatMap.seats && (
                                        <SeatMapFlight
                                            seats={currentSeatMap.seats}
                                            selectedSeats={selectedSeatNos}
                                            onSeatClick={handleSeatClick}
                                        />
                                    )}
                                    {transportMode === 'BUS' && currentSeatMap.seats && (
                                        <SeatMapBus
                                            seats={currentSeatMap.seats}
                                            selectedSeats={selectedSeatNos}
                                            onSeatClick={handleSeatClick}
                                        />
                                    )}
                                    {transportMode === 'TRAIN' && (
                                        <SeatMapTrain
                                            seats={currentCoachSeats}
                                            selectedSeats={selectedSeatNos}
                                            onSeatClick={handleSeatClick}
                                        />
                                    )}

                                    {/* Loading state */}
                                    {seatMapLoading && (
                                        <div className="text-center py-12 text-gray-500">
                                            <div className="w-8 h-8 border-2 border-primary-500 border-t-transparent rounded-full animate-spin mx-auto mb-3" />
                                            Loading seat map...
                                        </div>
                                    )}

                                    {/* No seats configured — show graceful fallback */}
                                    {!seatMapLoading && !currentSeatMap.seats && !currentSeatMap.coaches && currentSeatMap.tripId && (
                                        <div className="text-center py-10 text-gray-500">
                                            <div className="w-12 h-12 bg-gray-700 rounded-full flex items-center justify-center mx-auto mb-3">
                                                <MapPin className="w-6 h-6 text-gray-500" />
                                            </div>
                                            <p className="text-gray-400 font-medium">No seat map configured</p>
                                            <p className="text-gray-600 text-sm mt-1">This vehicle does not have a seat layout. You can proceed to general seating.</p>
                                        </div>
                                    )}

                                    <SeatLegend />
                                </div>

                                <div className="flex gap-4">
                                    <button onClick={() => setStep(0)} className="btn-secondary flex items-center gap-2">
                                        <ChevronLeft className="w-4 h-4" /> Back
                                    </button>
                                    <button
                                        onClick={() => setStep(2)}
                                        disabled={!allSeatsAssigned()}
                                        className="btn-primary flex-1 flex items-center justify-center gap-2 py-3 disabled:opacity-50 disabled:cursor-not-allowed"
                                    >
                                        Review & Pay <ChevronRight className="w-5 h-5" />
                                    </button>
                                </div>
                            </div>
                        )}

                        {/* STEP 2: Review & Pay */}
                        {step === 2 && (
                            <div className="animate-fade-in space-y-6">
                                <div className="glass-card p-6">
                                    <h3 className="text-white font-semibold mb-4">Booking Summary</h3>

                                    {passengers.map((p, i) => {
                                        const allLegSeats = legs.map((leg, li) => (seatAssignments[li] || {})[i])
                                        return (
                                            <div key={i} className="mb-4 last:mb-0 pb-4 last:pb-0 border-b border-white/5 last:border-0">
                                                <div className="flex items-center gap-2 mb-2">
                                                    <div className="w-6 h-6 bg-primary-600/30 rounded-full flex items-center justify-center text-xs font-bold text-primary-400">{i + 1}</div>
                                                    <span className="text-white font-semibold">{p.name}</span>
                                                </div>
                                                <div className="ml-8 space-y-1">
                                                    {legs.map((leg, li) => {
                                                        const seat = allLegSeats[li]
                                                        return (
                                                            <div key={li} className="flex items-center justify-between text-sm">
                                                                <span className="text-gray-400">{leg.origin} → {leg.destination}</span>
                                                                {seat ? (
                                                                    <span className="text-emerald-400 font-semibold">
                                                                        {seat.coachNo ? `${seat.coachNo}-` : ''}{seat.seatNo}
                                                                        {seat.seatClass ? ` (${seat.seatClass})` : ''}
                                                                        {seat.berthType ? ` · ${seat.berthType}` : ''}
                                                                    </span>
                                                                ) : (
                                                                    <span className="text-gray-600 italic text-xs">General</span>
                                                                )}
                                                            </div>
                                                        )
                                                    })}
                                                </div>
                                            </div>
                                        )
                                    })}
                                </div>

                                <div className="flex gap-4">
                                    <button onClick={() => setStep(1)} className="btn-secondary flex items-center gap-2">
                                        <ChevronLeft className="w-4 h-4" /> Back
                                    </button>
                                    <button
                                        onClick={handleBook}
                                        disabled={loading}
                                        className="btn-primary flex-1 flex items-center justify-center gap-2 text-base py-4"
                                    >
                                        {loading ? (
                                            <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin" />
                                        ) : (
                                            <CreditCard className="w-5 h-5" />
                                        )}
                                        {loading ? 'Processing...' : `Pay ₹${totalPrice.toLocaleString('en-IN')} via Stripe`}
                                    </button>
                                </div>
                            </div>
                        )}

                    </div>

                    {/* Right: Journey Summary */}
                    <div className="space-y-4">
                        <div className="glass-card p-5">
                            <h3 className="text-white font-semibold mb-4">Journey Summary</h3>
                            <JourneyTimeline legs={route.legs} compact={false} />
                            <div className="border-t border-white/5 mt-4 pt-4 space-y-2">
                                <div className="flex justify-between text-sm">
                                    <span className="text-gray-400">Passengers</span>
                                    <span className="text-white">{passengers.length}</span>
                                </div>
                                <div className="flex justify-between font-bold text-white">
                                    <span>Total</span>
                                    <span className="text-xl text-primary-400">₹{totalPrice.toLocaleString('en-IN')}</span>
                                </div>
                            </div>
                        </div>

                        {/* Seat assignments summary */}
                        {step >= 1 && Object.keys(seatAssignments).length > 0 && (
                            <div className="glass-card p-4">
                                <h4 className="text-sm font-semibold text-white mb-3">Seat Assignments</h4>
                                {legs.map((leg, li) => {
                                    const assignments = seatAssignments[li] || {}
                                    return Object.keys(assignments).length > 0 ? (
                                        <div key={li} className="mb-2">
                                            <div className="text-xs text-gray-500 mb-1">{leg.origin} → {leg.destination}</div>
                                            {Object.entries(assignments).map(([pi, seat]) => (
                                                <div key={pi} className="flex justify-between text-xs py-0.5">
                                                    <span className="text-gray-400">{passengers[pi]?.name}</span>
                                                    <span className="text-emerald-400 font-semibold">
                                                        {seat.coachNo ? `${seat.coachNo}-` : ''}{seat.seatNo}
                                                    </span>
                                                </div>
                                            ))}
                                        </div>
                                    ) : null
                                })}
                            </div>
                        )}

                        <div className="glass p-4 text-xs text-gray-500 leading-relaxed">
                            <CreditCard className="w-4 h-4 text-gray-400 mb-2" />
                            Payment is securely processed by Stripe. Your card details are never stored on our servers.
                        </div>
                    </div>
                </div>
            </div>
        </div>
    )
}

import { useEffect, useState } from 'react'
import { bookingApi } from '../api/axios'
import { useAuth } from '../context/AuthContext'
import JourneyTimeline from '../components/JourneyTimeline'
import toast from 'react-hot-toast'
import {
    Ticket, Clock, CheckCircle, XCircle, AlertCircle, ChevronDown, ChevronUp,
    Download, BarChart2, MapPin, Calendar, TrendingUp, Plane, Train, Bus,
    User, Settings, LogOut
} from 'lucide-react'
import { useNavigate } from 'react-router-dom'
import { SectionLoader } from '../components/Loaders'

const STATUS_STYLES = {
    PAID: 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20',
    PENDING: 'bg-yellow-500/10 text-yellow-400 border-yellow-500/20',
    CANCELLED: 'bg-red-500/10 text-red-400 border-red-500/20',
    PAYMENT_INITIATED: 'bg-blue-500/10 text-blue-400 border-blue-500/20',
    REFUNDED: 'bg-purple-500/10 text-purple-400 border-purple-500/20',
}

const STATUS_ICON = {
    PAID: <CheckCircle className="w-3.5 h-3.5" />,
    PENDING: <Clock className="w-3.5 h-3.5" />,
    CANCELLED: <XCircle className="w-3.5 h-3.5" />,
    PAYMENT_INITIATED: <AlertCircle className="w-3.5 h-3.5" />,
}

function BookingCard({ booking }) {
    const [expanded, setExpanded] = useState(false)

    const legs = booking.tickets?.map(t => ({
        tripId: t.ticketId,
        originCity: t.originCity,
        originStation: t.originCity,
        destinationCity: t.destinationCity,
        destinationStation: t.destinationCity,
        departureTime: t.departureTime,
        arrivalTime: t.arrivalTime,
        transportMode: t.transportMode,
        carrierName: t.carrierName,
        price: t.legPrice,
        layoverMinutesNextLeg: 0,
    })) || []

    const origin = legs[0]?.originCity || '—'
    const dest = legs[legs.length - 1]?.destinationCity || '—'
    const deptDate = legs[0]?.departureTime
        ? new Date(legs[0].departureTime).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' })
        : null

    const modeIcons = {
        FLIGHT: <Plane className="w-3 h-3 text-sky-500 dark:text-sky-400" />,
        TRAIN: <Train className="w-3 h-3 text-emerald-500 dark:text-emerald-400" />,
        BUS: <Bus className="w-3 h-3 text-amber-500 dark:text-amber-400" />,
    }

    const firstCarrier = legs[0]?.carrierName
    const originStation = legs[0]?.originStation && legs[0]?.originStation !== origin ? `${origin} (${legs[0].originStation})` : origin
    const destStation = legs[legs.length - 1]?.destinationStation && legs[legs.length - 1]?.destinationStation !== dest ? `${dest} (${legs[legs.length - 1].destinationStation})` : dest

    return (
        <div className={`glass-card overflow-hidden transition-all duration-300 ${expanded ? 'ring-1 ring-primary-500/20' : ''}`}>
            <div className="p-5 flex items-center justify-between gap-4">
                <div className="flex-1 min-w-0">
                    {/* Route: Station → Station */}
                    <div className="flex items-center gap-2 mb-1 flex-wrap">
                        <span className="text-gray-900 dark:text-white font-bold text-sm">
                            {originStation} → {destStation}
                        </span>
                        <span className={`inline-flex items-center gap-1 text-[11px] font-semibold px-2.5 py-0.5 rounded-full border ${STATUS_STYLES[booking.status] || STATUS_STYLES.PENDING}`}>
                            {STATUS_ICON[booking.status]}
                            {booking.status}
                        </span>
                    </div>
                    <div className="flex items-center gap-3 text-xs text-gray-500 flex-wrap">
                        <span className="text-gray-500 dark:text-gray-600">#{booking.bookingId}</span>
                        {deptDate && (
                            <span className="flex items-center gap-1 text-gray-500">
                                <Calendar className="w-3 h-3" />
                                {deptDate}
                            </span>
                        )}
                        {firstCarrier && (
                            <span className="text-gray-500">{firstCarrier}</span>
                        )}
                        {/* Mode icons */}
                        <div className="flex items-center gap-1">
                            {[...new Set(legs.map(l => l.transportMode))].map((m, i) => (
                                <span key={i}>{modeIcons[m]}</span>
                            ))}
                        </div>
                    </div>
                </div>

                <div className="flex items-center gap-3">
                    <div className="text-right">
                        <p className="text-xs text-gray-500">Total</p>
                        <p className="text-gray-900 dark:text-white font-bold text-lg">₹{Number(booking.totalPrice).toLocaleString('en-IN')}</p>
                    </div>
                    <button
                        onClick={() => setExpanded(v => !v)}
                        className="w-8 h-8 flex items-center justify-center rounded-lg bg-gray-100 dark:bg-dark-600/60 border border-gray-200 dark:border-white/8 hover:border-gray-300 dark:hover:border-white/15 hover:bg-gray-200 dark:hover:bg-dark-600 transition-all"
                    >
                        {expanded ? <ChevronUp className="w-4 h-4 text-gray-500 dark:text-gray-300" /> : <ChevronDown className="w-4 h-4 text-gray-500 dark:text-gray-300" />}
                    </button>
                </div>
            </div>

            {expanded && legs.length > 0 && (
                <div className="border-t border-white/5 px-5 pt-4 pb-5 animate-fade-in">
                    <JourneyTimeline legs={legs} />
                    {booking.status === 'PAID' && (
                        <div className="mt-4 flex justify-end">
                            <a
                                href={`/api/tickets/download/${booking.bookingId}`}
                                target="_blank"
                                rel="noopener noreferrer"
                                className="flex items-center gap-2 text-xs text-primary-400 hover:text-primary-300 bg-primary-500/10 border border-primary-500/20 px-3 py-2 rounded-lg transition-all hover:bg-primary-500/15"
                            >
                                <Download className="w-3.5 h-3.5" />
                                Download e-Ticket
                            </a>
                        </div>
                    )}
                </div>
            )}
        </div>
    )
}

const TABS = [
    { id: 'upcoming', label: 'Upcoming', statuses: ['PAID', 'PENDING', 'PAYMENT_INITIATED'] },
    { id: 'past', label: 'Past', statuses: ['CANCELLED', 'REFUNDED', 'COMPLETED'] },
]

export default function DashboardPage() {
    const { user, logout } = useAuth()
    const navigate = useNavigate()
    const [bookings, setBookings] = useState([])
    const [loading, setLoading] = useState(true)
    const [tab, setTab] = useState('upcoming')

    useEffect(() => {
        bookingApi.getUserBookings()
            .then(res => setBookings(res.data))
            .catch(() => toast.error('Failed to load bookings'))
            .finally(() => setLoading(false))
    }, [])

    const activeBookings = bookings.filter(b => ['PAID', 'PENDING', 'PAYMENT_INITIATED'].includes(b.status))
    const pastBookings = bookings.filter(b => ['CANCELLED', 'REFUNDED', 'COMPLETED'].includes(b.status))

    const displayedBookings = tab === 'upcoming' ? activeBookings : pastBookings
    const totalSpent = bookings.filter(b => b.status === 'PAID').reduce((s, b) => s + Number(b.totalPrice), 0)

    return (
        <div className="min-h-screen pt-20 pb-12 px-4">
            <div className="max-w-5xl mx-auto">

                {/* ── PROFILE HEADER ── */}
                <div className="glass-card p-6 mb-6 animate-slide-up">
                    <div className="flex items-center gap-5">
                        <div className="w-16 h-16 rounded-2xl bg-gradient-to-br from-primary-500 to-primary-700 flex items-center justify-center text-white text-2xl font-black shadow-lg shadow-primary-600/30 flex-shrink-0">
                            {user?.name?.charAt(0).toUpperCase()}
                        </div>
                        <div className="flex-1 min-w-0">
                            <h1 className="text-xl font-bold text-gray-900 dark:text-white">
                                Hey, {user?.name?.split(' ')[0]}! 👋
                            </h1>
                            <p className="text-gray-600 dark:text-gray-400 text-sm">{user?.email}</p>
                            <p className="text-xs text-gray-500 dark:text-gray-600 mt-0.5">Member since {new Date().getFullYear()}</p>
                        </div>
                        <div className="hidden sm:flex items-center gap-2">
                            <button
                                onClick={() => navigate('/')}
                                className="btn-primary text-sm py-2 px-4"
                            >
                                Book New Trip
                            </button>
                        </div>
                    </div>
                </div>

                {/* ── STATS ROW ── */}
                <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 mb-6">
                    {[
                        { label: 'Total Trips', value: bookings.length, icon: Ticket, color: 'text-primary-400 bg-primary-500/10' },
                        { label: 'Active', value: activeBookings.length, icon: CheckCircle, color: 'text-emerald-400 bg-emerald-500/10' },
                        { label: 'Past Trips', value: pastBookings.length, icon: Clock, color: 'text-gray-500 dark:text-gray-400 bg-gray-500/10' },
                        { label: 'Total Spent', value: `₹${totalSpent.toLocaleString('en-IN')}`, icon: TrendingUp, color: 'text-amber-400 bg-amber-500/10' },
                    ].map(s => {
                        const Icon = s.icon
                        return (
                            <div key={s.label} className="glass p-4">
                                <div className={`w-9 h-9 rounded-xl ${s.color} flex items-center justify-center mb-3`}>
                                    <Icon className={`w-4.5 h-4.5 ${s.color.split(' ')[0]}`} />
                                </div>
                                <p className="text-2xl font-black text-gray-900 dark:text-white">{s.value}</p>
                                <p className="text-gray-500 text-xs mt-0.5">{s.label}</p>
                            </div>
                        )
                    })}
                </div>

                {/* ── TABS + BOOKINGS ── */}
                <div>
                    <div className="flex items-center gap-1 mb-5 bg-gray-100 dark:bg-dark-700/40 border border-gray-200 dark:border-white/5 p-1 rounded-xl w-fit">
                        {TABS.map(t => (
                            <button
                                key={t.id}
                                onClick={() => setTab(t.id)}
                                className={`px-5 py-2 rounded-lg text-sm font-semibold transition-all duration-200 ${tab === t.id
                                    ? 'bg-primary-600 text-white shadow-md'
                                    : 'text-gray-600 dark:text-gray-400 hover:text-gray-900 dark:hover:text-white'
                                    }`}
                            >
                                {t.label}
                                {t.id === 'upcoming' && activeBookings.length > 0 && (
                                    <span className="ml-2 bg-white/20 text-xs px-1.5 py-0.5 rounded-full">{activeBookings.length}</span>
                                )}
                            </button>
                        ))}
                    </div>

                    {loading ? (
                        <div className="space-y-4">
                            {[1, 2].map(i => (
                                <div key={i} className="glass-card p-5 animate-pulse">
                                    <div className="h-5 w-40 bg-gray-200 dark:bg-dark-600 rounded mb-2" />
                                    <div className="h-4 w-24 bg-gray-200 dark:bg-dark-600 rounded" />
                                </div>
                            ))}
                        </div>
                    ) : displayedBookings.length === 0 ? (
                        <div className="glass-card p-14 text-center">
                            <Ticket className="w-12 h-12 text-gray-400 dark:text-gray-600 mx-auto mb-4" />
                            <h3 className="text-gray-900 dark:text-gray-300 font-semibold mb-2">
                                {tab === 'upcoming' ? 'No upcoming trips' : 'No past trips'}
                            </h3>
                            <p className="text-gray-500 text-sm mb-6">
                                {tab === 'upcoming' ? 'Plan your next multi-modal journey!' : 'Your completed trips will appear here.'}
                            </p>
                            {tab === 'upcoming' && (
                                <button onClick={() => navigate('/')} className="btn-primary">
                                    Search Routes
                                </button>
                            )}
                        </div>
                    ) : (
                        <div className="space-y-4">
                            {displayedBookings.map(b => <BookingCard key={b.bookingId} booking={b} />)}
                        </div>
                    )}
                </div>
            </div>
        </div>
    )
}

import { useState } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import { useAuth } from '../context/AuthContext'
import { authApi } from '../api/axios'
import toast from 'react-hot-toast'
import { Eye, EyeOff, Plane, ArrowRight, Phone, KeyRound, ChevronRight } from 'lucide-react'
import { ButtonSpinner } from '../components/Loaders'

/* ───────── shared input wrapper ───────── */
function FloatInput({ id, label, type = 'text', value, onChange, required, right, autoComplete }) {
    return (
        <div className="relative">
            <input
                id={id}
                type={type}
                value={value}
                onChange={onChange}
                placeholder=" "
                required={required}
                autoComplete={autoComplete}
                className="
                    peer w-full
                    bg-gray-50 dark:bg-dark-700/60
                    border border-gray-200 dark:border-white/8
                    text-gray-900 dark:text-white
                    placeholder-transparent
                    px-4 pt-6 pb-2
                    rounded-xl
                    focus:outline-none focus:border-primary-500 focus:ring-1 focus:ring-primary-500/30
                    transition-all duration-200 text-sm
                    pr-11
                "
            />
            <label
                htmlFor={id}
                className="
                    absolute left-4 top-2
                    text-[11px] font-semibold uppercase tracking-wider
                    text-gray-400 dark:text-gray-500
                    peer-placeholder-shown:top-3.5 peer-placeholder-shown:text-sm peer-placeholder-shown:font-normal peer-placeholder-shown:normal-case peer-placeholder-shown:tracking-normal peer-placeholder-shown:text-gray-400
                    peer-focus:top-2 peer-focus:text-[11px] peer-focus:font-semibold peer-focus:uppercase peer-focus:tracking-wider peer-focus:text-primary-500
                    transition-all duration-200 pointer-events-none
                "
            >
                {label}
            </label>
            {right && (
                <div className="absolute right-3 top-1/2 -translate-y-1/2">
                    {right}
                </div>
            )}
        </div>
    )
}

/* ───────── MAIN LOGIN PAGE ───────── */
export default function LoginPage() {
    const { login } = useAuth()
    const navigate = useNavigate()
    const [form, setForm] = useState({ email: '', password: '' })
    const [showPwd, setShowPwd] = useState(false)
    const [loading, setLoading] = useState(false)

    const handleSubmit = async (e) => {
        e.preventDefault()
        setLoading(true)
        try {
            await login(form)
            toast.success('Welcome back! 🎉')
            navigate('/dashboard')
        } catch (err) {
            toast.error(err.response?.data?.message || 'Invalid email or password')
        } finally {
            setLoading(false)
