import React, { useEffect, useState } from 'react'
import { useSearchParams, useNavigate, Link } from 'react-router-dom'
import { bookingApi, ticketApi } from '../api/axios'
import { CheckCircle, CheckCircle2, Ticket, ArrowRight, Home, LayoutDashboard, Download } from 'lucide-react'
import { PageLoader } from '../components/Loaders'

export default function PaymentSuccessPage() {
    const [params] = useSearchParams()
    const navigate = useNavigate()
    const [booking, setBooking] = useState(null)
    const [loading, setLoading] = useState(true)
    const [error, setError] = useState(false)

    useEffect(() => {
        // The booking is confirmed via webhook. We poll once to get it.
        const fetchBooking = async () => {
            try {
                const res = await bookingApi.getUserBookings()
                const latest = res.data?.[0]
                if (latest && latest.status === 'PAID') {
                    setBooking(latest)
                    setLoading(false)
                } else {
                    // Retry in 2 seconds if not yet PAID
                    setTimeout(fetchBooking, 2000)
                }
            } catch {
                setLoading(false)
                setError(true)
            }
        }
        fetchBooking()
    }, [])

    const handleDownload = async (ticketId) => {
        try {
            const response = await ticketApi.download(ticketId)
            const url = window.URL.createObjectURL(new Blob([response.data]))
            const a = document.createElement('a')
            a.href = url
            a.download = `ticket_${ticketId}.pdf`
            document.body.appendChild(a)
            a.click()
            window.URL.revokeObjectURL(url)
        } catch (err) {
            // toast.error('Failed to download ticket. Please try again.') // Removed toast
            console.error('Failed to download ticket:', err)
        }
    }

    return (
        <div className="min-h-screen pt-24 pb-16 px-4 bg-[radial-gradient(circle_at_top,_var(--tw-gradient-stops))] from-emerald-900/20 via-transparent to-transparent">
            <div className="max-w-xl mx-auto pt-20 px-4">
                {loading ? (
                    <PageLoader />
                ) : error ? (
                    <div className="glass-card p-12 text-center border-red-500/20">
                        <p className="text-gray-400 mb-6">We're taking a bit longer than expected to confirm your payment.</p>
                        <button onClick={() => navigate('/dashboard')} className="btn-primary py-3 px-8">Go to Dashboard</button>
                    </div>
                ) : booking ? (
                    <div className="animate-fade-in">
                        {/* Success Banner */}
                        <div className="text-center mb-12 animate-slide-up">
                            <div className="relative inline-flex">
                                <div className="absolute inset-0 bg-emerald-500/30 rounded-full blur-3xl animate-pulse-slow" />
                                <div className="relative w-24 h-24 bg-emerald-500/10 border-2 border-emerald-500/30 rounded-full flex items-center justify-center mb-6">
                                    <CheckCircle className="w-12 h-12 text-emerald-400" />
                                </div>
                            </div>
                            <h1 className="text-5xl font-black text-white mt-4 mb-3 tracking-tight">Booking Confirmed!</h1>
                            <p className="text-gray-400 text-lg max-w-lg mx-auto leading-relaxed">
                                Your electronic tickets have been generated and sent to your email. You can also download them below.
                            </p>
                        </div>

                        <div className="grid gap-8">
                            {/* Summary Card */}
                            <div className="glass-card p-8 border-emerald-500/20">
                                <div className="flex flex-col sm:flex-row items-center justify-between gap-6 mb-8 pb-8 border-b border-white/5">
                                    <div>
                                        <p className="text-xs text-gray-500 uppercase tracking-widest font-bold mb-1">Booking Reference</p>
                                        <p className="text-3xl font-black text-white italic">#TRIP-{booking.bookingId}</p>
                                    </div>
                                    <div className="sm:text-right">
                                        <p className="text-xs text-gray-500 uppercase tracking-widest font-bold mb-1">Total Paid</p>
                                        <p className="text-3xl font-black text-emerald-400">₹{Number(booking.totalPrice).toLocaleString('en-IN')}</p>
                                    </div>
                                </div>

                                <div className="space-y-12">
                                    {booking.tickets?.map((ticket, idx) => (
                                        <div key={ticket.ticketId} className="relative group">
                                            <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-6 p-6 rounded-2xl bg-white/5 border border-white/5 hover:border-emerald-500/30 transition-all duration-300">
                                                <div className="flex-1">
                                                    <div className="flex items-center gap-3 mb-4">
                                                        <span className="px-2.5 py-1 rounded bg-emerald-500/20 text-emerald-400 text-[10px] font-black uppercase">Leg {idx + 1}</span>
                                                        <span className="text-white/40 text-xs">ID: TL-{ticket.ticketId}</span>
                                                        <span className="px-2 py-0.5 rounded bg-blue-500/20 text-blue-300 text-[10px] font-bold uppercase">{ticket.transportMode}</span>
                                                    </div>
                                                    <div className="flex items-center gap-4 mb-3">
                                                        <span className="text-xl font-bold text-white">{ticket.originCity}</span>
                                                        <ArrowRight className="w-4 h-4 text-emerald-500" />
                                                        <span className="text-xl font-bold text-white">{ticket.destinationCity}</span>
                                                    </div>
                                                    <div className="space-y-1 text-sm text-gray-400">
                                                        <div>
                                                            Passenger: <span className="text-white font-semibold">{ticket.passengerName}</span>
                                                        </div>
                                                        <div className="flex items-center gap-2 flex-wrap">
                                                            <span>Seat:</span>
                                                            <span className="text-emerald-400 font-bold text-base">
                                                                {ticket.coachNumber ? `${ticket.coachNumber} - ` : ''}{ticket.seatNumber || 'General'}
                                                            </span>
                                                            {ticket.seatClass && (
                                                                <span className="px-2 py-0.5 bg-purple-500/20 text-purple-300 rounded text-xs font-semibold border border-purple-500/30">
                                                                    {ticket.seatClass}
                                                                </span>
                                                            )}
                                                            {ticket.berthType && (
                                                                <span className="px-2 py-0.5 bg-amber-500/20 text-amber-300 rounded text-xs font-semibold border border-amber-500/30">
                                                                    {ticket.berthType === 'L' ? 'Lower' : ticket.berthType === 'M' ? 'Middle' : ticket.berthType === 'U' ? 'Upper' : ticket.berthType === 'SL' ? 'Side Lower' : ticket.berthType === 'SU' ? 'Side Upper' : ticket.berthType} Berth
                                                                </span>
                                                            )}
                                                        </div>
                                                    </div>
                                                </div>

                                                <div className="flex flex-col items-center gap-3 md:pl-6 md:border-l border-white/10 shrink-0">
                                                    {ticket.qrCode && (
                                                        <div className="p-2 bg-white rounded-lg shadow-2xl">
                                                            <img src={`data:image/png;base64,${ticket.qrCode}`} alt="Ticket QR" className="w-16 h-16" />
                                                        </div>
                                                    )}
                                                    <button
                                                        onClick={() => handleDownload(ticket.ticketId)}
                                                        className="flex items-center gap-2 text-xs font-bold text-emerald-400 hover:text-emerald-300 transition-colors bg-emerald-500/10 px-4 py-2 rounded-full border border-emerald-500/20"
                                                    >
                                                        <Download className="w-3.5 h-3.5" /> Download PDF
                                                    </button>
                                                </div>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>

                            {/* Actions */}
                            <div className="flex flex-col sm:flex-row gap-4 justify-center py-4">
                                <Link to="/dashboard" className="btn-primary px-10 h-14 flex items-center justify-center gap-2 text-lg">
                                    <LayoutDashboard className="w-5 h-5" /> Travel Dashboard
                                </Link>
                                <Link to="/" className="btn-outline px-10 h-14 flex items-center justify-center gap-2 text-lg">
                                    Plan Another Trip
                                </Link>
                            </div>
                        </div>
                    </div>
                ) : (
                    <div className="glass-card p-12 text-center border-red-500/20">
                        <p className="text-gray-400 mb-6">We're taking a bit longer than expected to confirm your payment.</p>
                        <Link to="/dashboard" className="btn-primary py-3 px-8">Go to Dashboard</Link>
                    </div>
                )}
            </div>
        </div>
    )
}

import { useState, useEffect, useMemo } from 'react'
import { useLocation, useNavigate } from 'react-router-dom'
import { searchApi } from '../api/axios'
import SearchBar from '../components/SearchBar'
import JourneyCard from '../components/JourneyCard'
import toast from 'react-hot-toast'
import { RouteSkeleton } from '../components/Loaders'
import {
    SlidersHorizontal, AlertCircle, Zap, Coins, Scale, X,
    Plane, Train, Bus, ChevronDown, ChevronUp, BarChart2
} from 'lucide-react'

const OPT_BUTTONS = [
    { id: 'BALANCED', label: 'Balanced', icon: Scale, color: 'text-purple-400 border-purple-500/30 bg-purple-500/10' },
    { id: 'CHEAPEST', label: 'Cheapest', icon: Coins, color: 'text-emerald-400 border-emerald-500/30 bg-emerald-500/10' },
    { id: 'FASTEST', label: 'Fastest', icon: Zap, color: 'text-yellow-400 border-yellow-500/30 bg-yellow-500/10' },
]

function FilterPanel({ filters, onChange, routes }) {
    const [open, setOpen] = useState(false)

    const priceRange = routes.length
        ? { min: Math.min(...routes.map(r => Number(r.totalPrice))), max: Math.max(...routes.map(r => Number(r.totalPrice))) }
        : { min: 0, max: 10000 }

    return (
        <div className="mb-5">
            <button
                onClick={() => setOpen(v => !v)}
                className="flex items-center gap-2 px-4 py-2 rounded-xl bg-white dark:bg-dark-700/60 border border-gray-200 dark:border-white/8 text-sm text-gray-600 dark:text-gray-300 hover:text-gray-900 dark:hover:text-white hover:border-gray-300 dark:hover:border-white/15 transition-all"
            >
                <SlidersHorizontal className="w-4 h-4" />
                Filters
                {open ? <ChevronUp className="w-4 h-4 ml-auto" /> : <ChevronDown className="w-4 h-4 ml-auto" />}
            </button>

            {open && (
                <div className="mt-3 glass-card p-5 animate-slide-down">
                    <div className="grid grid-cols-2 sm:grid-cols-4 gap-5">

                        {/* Transport mode */}
                        <div>
                            <h4 className="text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-2">Mode</h4>
                            <div className="flex flex-col gap-1.5">
                                {['All', 'FLIGHT', 'TRAIN', 'BUS'].map(m => (
                                    <button
                                        key={m}
                                        onClick={() => onChange({ ...filters, mode: m === 'All' ? '' : m })}
                                        className={`text-left text-sm px-3 py-1.5 rounded-lg transition-all ${(filters.mode === m || (!filters.mode && m === 'All'))
                                                ? 'bg-primary-600/20 text-primary-400 border border-primary-500/30'
                                                : 'text-gray-400 hover:text-white hover:bg-dark-600'
                                            }`}
                                    >
                                        {m === 'FLIGHT' ? '✈️' : m === 'TRAIN' ? '🚂' : m === 'BUS' ? '🚌' : '🌐'} {m}
                                    </button>
                                ))}
                            </div>
                        </div>

                        {/* Max price */}
                        <div>
                            <h4 className="text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-2">Max Price</h4>
                            <input
                                type="range"
                                min={priceRange.min}
                                max={priceRange.max}
                                value={filters.maxPrice || priceRange.max}
                                onChange={e => onChange({ ...filters, maxPrice: Number(e.target.value) })}
                                className="w-full accent-primary-500"
                            />
                            <p className="text-sm text-primary-400 font-semibold mt-1">₹{(filters.maxPrice || priceRange.max).toLocaleString('en-IN')}</p>
                        </div>

                        {/* Max transfers */}
                        <div>
                            <h4 className="text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-2">Max Stops</h4>
                            {[0, 1, 2].map(n => (
                                <button
                                    key={n}
                                    onClick={() => onChange({ ...filters, maxTransfers: filters.maxTransfers === n ? null : n })}
                                    className={`mr-2 mb-2 px-3 py-1 rounded-full text-xs border transition-all ${filters.maxTransfers === n
                                            ? 'bg-primary-600/20 text-primary-400 border-primary-500/30'
                                            : 'border-white/8 text-gray-400 hover:border-white/15 hover:text-white'
                                        }`}
                                >
                                    {n === 0 ? 'Non-stop' : `${n} stop${n > 1 ? 's' : ''}`}
                                </button>
                            ))}
                        </div>

                        {/* Max duration */}
                        <div>
                            <h4 className="text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-2">Max Duration</h4>
                            <input
                                type="range"
                                min={60}
                                max={2400}
                                step={60}
                                value={filters.maxDuration || 2400}
                                onChange={e => onChange({ ...filters, maxDuration: Number(e.target.value) })}
                                className="w-full accent-primary-500"
                            />
                            <p className="text-sm text-primary-400 font-semibold mt-1">
                                {Math.floor((filters.maxDuration || 2400) / 60)}h {(filters.maxDuration || 2400) % 60}m
                            </p>
                        </div>
                    </div>

                    <div className="flex justify-end mt-4">
                        <button
                            onClick={() => onChange({ mode: '', maxPrice: null, maxTransfers: null, maxDuration: null })}
                            className="flex items-center gap-1.5 text-xs text-gray-500 hover:text-white transition-colors"
                        >
                            <X className="w-3.5 h-3.5" />
                            Reset Filters
                        </button>
                    </div>
                </div>
            )}
        </div>
    )
}

export default function SearchResultsPage() {
    const location = useLocation()
    const navigate = useNavigate()
    const [routes, setRoutes] = useState([])
    const [loading, setLoading] = useState(false)
    const [searchParams, setSearchParams] = useState(location.state?.searchParams || null)
    const [selectedRoute, setSelectedRoute] = useState(null)
    const [optMode, setOptMode] = useState(searchParams?.optimizationMode || 'BALANCED')
    const [filters, setFilters] = useState({ mode: '', maxPrice: null, maxTransfers: null, maxDuration: null })

    // Re-search instantly when optMode changes
    useEffect(() => {
        if (searchParams) {
            const newParams = { ...searchParams, optimizationMode: optMode }
            doSearch(newParams)
        }
    }, [optMode])

    const doSearch = async (params) => {
        setLoading(true)
        setRoutes([])
        setSelectedRoute(null)
        setSearchParams(params)
        try {
            const res = await searchApi.findRoutes(params)
            setRoutes(res.data)
            if (res.data.length === 0) toast('No routes found. Try a different date or city.', { icon: '🔍' })
        } catch (err) {
            toast.error(err.response?.data?.message || 'Search failed. Please try again.')
        } finally {
            setLoading(false)
        }
    }

    // Apply client-side filters
    const filteredRoutes = useMemo(() => {
        return routes.filter(r => {
            if (filters.mode && !r.legs?.some(l => l.transportMode === filters.mode)) return false
            if (filters.maxPrice && Number(r.totalPrice) > filters.maxPrice) return false
            if (filters.maxTransfers !== null && r.transfers > filters.maxTransfers) return false
            if (filters.maxDuration && r.totalDurationMinutes > filters.maxDuration) return false
            return true
        })
    }, [routes, filters])

    const handleBook = () => {
        if (!selectedRoute) { toast.error('Please select a route first'); return }
        navigate('/booking', { state: { route: selectedRoute, searchParams } })
    }

    return (
        <div className="min-h-screen pt-20 pb-20 px-4">
            <div className="max-w-5xl mx-auto">
                {/* Search Bar */}
                <div className="mb-6 animate-slide-up">
                    <SearchBar initialValues={searchParams} onSearch={doSearch} loading={loading} />
                </div>

                {/* Optimization Mode - Instant Switch */}
                {!loading && routes.length > 0 && (
                    <div className="flex items-center gap-3 mb-5 animate-fade-in flex-wrap">
                        <span className="text-gray-500 text-xs font-semibold uppercase tracking-wider">Sort by:</span>
                        {OPT_BUTTONS.map(btn => {
                            const Icon = btn.icon
                            return (
                                <button
                                    key={btn.id}
                                    onClick={() => setOptMode(btn.id)}
                                    className={`flex items-center gap-1.5 px-4 py-2 rounded-xl text-sm font-semibold border transition-all duration-200 ${optMode === btn.id
                                            ? `${btn.color} scale-105`
                                            : 'border-gray-200 dark:border-white/8 text-gray-500 hover:text-gray-800 dark:hover:text-gray-300 hover:border-gray-300 dark:hover:border-white/15'
                                        }`}
                                >
                                    <Icon className="w-3.5 h-3.5" />
                                    {btn.label}
                                </button>
                            )
                        })}
                    </div>
                )}

                {/* Filter Panel */}
                {!loading && routes.length > 0 && (
                    <FilterPanel filters={filters} onChange={setFilters} routes={routes} />
                )}

                {/* Results Header */}
                {!loading && filteredRoutes.length > 0 && (
                    <div className="flex items-center justify-between mb-4 animate-fade-in">
                        <p className="text-gray-500 dark:text-gray-400 text-sm">
                            <span className="text-gray-900 dark:text-white font-semibold">{filteredRoutes.length}</span> routes found
                            {searchParams?.originCity && searchParams?.destinationCity && ` for ${searchParams.originCity} → ${searchParams.destinationCity}`}
                        </p>
                        <div className="flex items-center gap-1.5 text-xs text-gray-600">
                            <BarChart2 className="w-3.5 h-3.5" />
                            <span>{optMode} mode</span>
                        </div>
                    </div>
                )}

                {/* LOADER */}
                {loading && (
                    <div className="py-12">
                        <RouteSkeleton />
                    </div>
                )}

                {/* Route Results */}
                {!loading && filteredRoutes.length > 0 && (
                    <div className="space-y-4 animate-fade-in">
                        {filteredRoutes.map((route, idx) => (
                            <JourneyCard
                                key={idx}
                                route={route}
                                selected={selectedRoute === route}
                                onSelect={setSelectedRoute}
                            />
                        ))}
                    </div>
                )}

                {/* Empty State */}
                {!loading && routes.length > 0 && filteredRoutes.length === 0 && (
                    <div className="text-center py-16 animate-fade-in">
                        <SlidersHorizontal className="w-12 h-12 text-gray-600 mx-auto mb-3" />
                        <h3 className="text-gray-800 dark:text-gray-300 font-semibold mb-1">No routes match your filters</h3>
                        <p className="text-gray-500 text-sm mb-4">Try relaxing your filter criteria</p>
                        <button onClick={() => setFilters({ mode: '', maxPrice: null, maxTransfers: null, maxDuration: null })} className="btn-outline text-sm">
                            Clear All Filters
                        </button>
                    </div>
                )}

                {!loading && routes.length === 0 && searchParams && (
                    <div className="text-center py-20 animate-fade-in">
                        <AlertCircle className="w-16 h-16 text-gray-600 mx-auto mb-4" />
                        <h3 className="text-xl font-semibold text-gray-800 dark:text-gray-300 mb-2">No routes found</h3>
                        <p className="text-gray-500 text-sm max-w-md mx-auto">
                            No trips between <strong className="text-gray-800 dark:text-gray-300">{searchParams.originCity}</strong> and{' '}
                            <strong className="text-gray-800 dark:text-gray-300">{searchParams.destinationCity}</strong> on this date.
                            <br />Try a different date or nearby city.
                        </p>
                    </div>
                )}

                {!loading && !searchParams && (
                    <div className="text-center py-20 text-gray-600 text-sm">
                        Use the search bar above to find routes.
                    </div>
                )}

                {/* Sticky Book Button */}
                {selectedRoute && (
                    <div className="fixed bottom-6 left-0 right-0 flex justify-center z-40 px-4 animate-slide-up">
                        <div className="glass-card px-6 py-4 flex items-center gap-6 shadow-2xl shadow-black/60">
                            <div>
                                <p className="text-xs text-gray-500">Selected route total</p>
                                <p className="text-xl font-bold text-gray-900 dark:text-white">₹{Number(selectedRoute.totalPrice).toLocaleString('en-IN')}</p>
                            </div>
                            <button onClick={handleBook} className="btn-primary text-base px-8 flex items-center gap-2 group">
                                Continue to Booking
                                <span className="group-hover:translate-x-0.5 transition-transform">→</span>
                            </button>
                        </div>
                    </div>
                )}
            </div>
        </div>
    )
}

import { useState, useEffect } from 'react'
import { useLocation, useNavigate, Link } from 'react-router-dom'
import { useAuth } from '../context/AuthContext'
import toast from 'react-hot-toast'
import { Mail, ArrowRight, ShieldCheck, CheckCircle2 } from 'lucide-react'
import { authApi } from '../api/axios'
import { ButtonSpinner } from '../components/Loaders'

export default function VerifyEmailPage() {
    const { verifyEmail } = useAuth()
    const location = useLocation()
    const navigate = useNavigate()
    const [otp, setOtp] = useState('')
    const [loading, setLoading] = useState(false)
    const email = location.state?.email

    useEffect(() => {
        if (!email) {
            toast.error('Session expired. Please register again.')
            navigate('/register')
        }
    }, [email, navigate])

    const handleSubmit = async (e) => {
        e.preventDefault()
        if (otp.length !== 6) {
            toast.error('Please enter a 6-digit OTP')
            return
        }
        setLoading(true)
        try {
            await verifyEmail({ email, otp })
            toast.success('Email verified! Redirecting to dashboard...')
            navigate('/dashboard')
        } catch (err) {
            toast.error(err.response?.data?.message || 'Verification failed')
        } finally {
            setLoading(false)
        }
    }

    return (
        <div className="min-h-screen pt-16 flex items-center justify-center px-4">
            <div className="absolute top-1/3 left-1/4 w-72 h-72 bg-blue-600/10 rounded-full blur-3xl pointer-events-none" />

            <div className="w-full max-w-md relative z-10 animate-slide-up">
                <div className="text-center mb-8">
                    <div className="inline-flex w-14 h-14 bg-primary-600 rounded-2xl items-center justify-center mb-4 shadow-lg shadow-primary-600/30">
                        <Mail className="w-7 h-7 text-white" />
                    </div>
                    <h1 className="text-3xl font-bold text-white">Verify your email</h1>
                    <p className="text-gray-400 mt-2">
                        We've sent a 6-digit code to <br />
                        <span className="text-primary-400 font-medium">{email}</span>
                    </p>
                </div>

                <form onSubmit={handleSubmit} className="glass-card p-8 space-y-6">
                    <div>
                        <label className="block text-sm font-medium text-gray-300 mb-4 text-center">
                            Enter Verification Code
                        </label>
                        <input
                            type="text"
                            maxLength={6}
                            value={otp}
                            onChange={(e) => setOtp(e.target.value.replace(/\D/g, ''))}
                            required
                            className="w-full bg-gray-900/50 border border-gray-700 rounded-xl py-4 text-center text-3xl font-bold tracking-[0.5em] text-white focus:ring-2 focus:ring-primary-500 focus:border-transparent outline-none transition-all"
                            placeholder="000000"
                        />
                    </div>

                    <button
                        type="submit"
                        disabled={loading || otp.length !== 6}
                        className="btn-primary w-full group py-3.5 mt-8 disabled:opacity-50 disabled:bg-primary-500 disabled:border-transparent flex items-center justify-center gap-2"
                    >
                        {loading 
                            ? <ButtonSpinner />
                            : <>Verify Email <ArrowRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" /></>
                        }
                    </button>

                    <div className="text-center">
                        <button
                            type="button"
                            onClick={() => toast.success('A new OTP has been sent (Mocked)')}
                            className="text-sm text-gray-500 hover:text-primary-400 transition-colors"
                        >
                            Didn't receive the code? Resend
                        </button>
                    </div>
                </form>

                <div className="text-center mt-8">
                    <button
                        onClick={() => navigate('/register')}
                        className="text-gray-500 hover:text-white inline-flex items-center gap-2 text-sm transition-colors"
                    >
                        Back to Register
                    </button>
                </div>
            </div>
        </div>
    )
}

import React from 'react'
import { Plus, Trash2, AlertCircle } from 'lucide-react'
